using System.Diagnostics;
using TextAnalysis;

const int WarmupIterations = 50;
const int MeasureIterations = 500;

// Setup
var small = "The quick brown fox jumps over the lazy dog";
var large = string.Join(" ", Enumerable.Repeat(
    "The quick brown fox jumps over the lazy dog and runs across the wide open field while birds sing melodiously", 200));
var smallAnalyzer = new TextAnalyzer(small);
var largeAnalyzer = new TextAnalyzer(large);

Console.WriteLine($"Runtime: {System.Runtime.InteropServices.RuntimeInformation.FrameworkDescription}");
Console.WriteLine($"Warmup: {WarmupIterations} iterations, Measure: {MeasureIterations} iterations");
Console.WriteLine();

Benchmark("AverageWordLength_Small", () => smallAnalyzer.AverageWordLength());
Benchmark("AverageWordLength_Large", () => largeAnalyzer.AverageWordLength());
Benchmark("WordLengthHistogram_Small", () => smallAnalyzer.WordLengthHistogram());
Benchmark("WordLengthHistogram_Large", () => largeAnalyzer.WordLengthHistogram());
Benchmark("UniqueWordCount_Small", () => smallAnalyzer.UniqueWordCount());
Benchmark("UniqueWordCount_Large", () => largeAnalyzer.UniqueWordCount());

void Benchmark(string name, Action action)
{
    // Warmup
    for (int i = 0; i < WarmupIterations; i++) action();

    // Collect individual iteration times
    var times = new double[MeasureIterations];
    for (int i = 0; i < MeasureIterations; i++)
    {
        var sw = Stopwatch.StartNew();
        action();
        sw.Stop();
        times[i] = sw.Elapsed.TotalNanoseconds;
    }

    Array.Sort(times);
    var mean = times.Average();
    var median = times[MeasureIterations / 2];
    var p95 = times[(int)(MeasureIterations * 0.95)];

    Console.WriteLine($"{name,-30} Mean: {FormatTime(mean),10} | Median: {FormatTime(median),10} | P95: {FormatTime(p95),10}");
}

string FormatTime(double ns)
{
    if (ns < 1000) return $"{ns:F1} ns";
    if (ns < 1_000_000) return $"{ns / 1000:F2} us";
    return $"{ns / 1_000_000:F2} ms";
}

